public void testCanonicalNamesAdditional1()
{
    TypeFactory tf = TypeFactory.defaultInstance();
    // Test with Optional which is another ReferenceType
    JavaType t = tf.constructType(new TypeReference<java.util.Optional<Integer>>() { });
    String can = t.toCanonical();
    assertEquals("java.util.Optional<java.lang.Integer>", can);
    assertEquals(t, tf.constructFromCanonical(can));
}

public void testCanonicalNamesAdditional2()
{
    TypeFactory tf = TypeFactory.defaultInstance();
    // Test with nested ReferenceType
    JavaType t = tf.constructType(new TypeReference<java.util.concurrent.atomic.AtomicReference<java.util.concurrent.atomic.AtomicReference<String>>>() { });
    String can = t.toCanonical();
    assertEquals("java.util.concurrent.atomic.AtomicReference<java.util.concurrent.atomic.AtomicReference<java.lang.String>>", can);
    assertEquals(t, tf.constructFromCanonical(can));
}

public void testCanonicalNamesAdditional3()
{
    TypeFactory tf = TypeFactory.defaultInstance();
    // Test with WeakReference which is another common ReferenceType
    JavaType t = tf.constructType(new TypeReference<java.lang.ref.WeakReference<Double>>() { });
    String can = t.toCanonical();
    assertEquals("java.lang.ref.WeakReference<java.lang.Double>", can);
    assertEquals(t, tf.constructFromCanonical(can));
}
